using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Build the chat client with tool support ---
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ]
};

// --- Agent system prompt ---
var systemPrompt = """
    You are a research agent. Your job is to research a topic the user provides.

    Follow this process:
    1. Break the topic into 2-3 key search queries.
    2. Use the SearchWeb tool to find information for each query.
    3. Use the AddNote tool to record important findings as you go.
    4. After gathering enough information, use GetNotes to review what you've collected.
    5. Provide a final comprehensive summary to the user.

    Always cite your sources. Be thorough but concise.
    """;

// --- Main interaction loop ---
Console.WriteLine("🔬 Research Agent Ready");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.WriteLine();

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\n📖 Researching: {topic}\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
    };

    var response = await client.GetResponseAsync(messages, chatOptions);
    Console.WriteLine(response.Text);
    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

// --- Web Search Tool ---
public sealed class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Searches the web for a given query and returns relevant results. Use this to find information about a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Use DuckDuckGo Instant Answer API (no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await Http.GetStringAsync(url);
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract/summary
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"[{abstractSource}]: {abstractText}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text))
                        results.Add($"- {text.GetString()}");
                }
            }

            if (results.Count == 0)
                return $"No detailed results found for '{query}'. Try a more specific query.";

            return string.Join("\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }
}

// --- Notebook Tool ---
public sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Adds a research note. Use this to record important findings, facts, or quotes discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note added ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Returns all research notes collected so far. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        var result = $"=== Research Notes ({_notes.Count}) ===\n";
        for (var i = 0; i < _notes.Count; i++)
            result += $"\n[{i + 1}] {_notes[i]}";
        return result;
    }
}

